INSERT OR IGNORE INTO chapter (id,tier,chapter_no,title,description,`order`,status,createdAt,updatedAt) VALUES ('14-trust-assets',2,14,'TRUST ASSETS','Xay dung tai san dang tin cay',14,'draft','2026-06-20T11:59:37Z','2026-06-20T11:59:37Z');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('bf40e5c6-ba91-4c02-89a3-c345ca9d5e27','14-trust-assets',NULL,2,'14.1 Bức tranh toàn cảnh - 5 trụ cột của Trust Assets','141-buc-tranh-toan-canh-5-tru-cot-cua-trust-assets',0,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('443d6318-1cf2-4993-93e9-50cc15e66554','bf40e5c6-ba91-4c02-89a3-c345ca9d5e27',0,'text','Trong hành trình vận hành phòng khám và nỗ lực lan tỏa tinh thần để mọi người thực sự gạt bỏ nỗi sợ và bắt đầu "thích làm răng", tôi nhận ra một quy luật tâm lý vô cùng rõ ràng: Khách hàng ngày nay rất thông minh và đầy hoài nghi. Họ không bao giờ vội vã tin vào những lời quảng cáo có cánh hay những cam kết suông mà chúng ta tự nói về mình.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('67caa586-6b42-46e2-9682-f994af7c5361','bf40e5c6-ba91-4c02-89a3-c345ca9d5e27',1,'text','Để một người lạ mặt từ trên mạng bước vào phòng khám và giao phó sức khỏe nụ cười của họ cho bạn, chúng ta cần một hệ thống bằng chứng thép. Đó chính là **Trust Assets (Tài sản niềm tin)**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e544c50c-36c9-4f6e-8438-bd0bf0edc920','bf40e5c6-ba91-4c02-89a3-c345ca9d5e27',2,'text','Nếu Content là mồi lửa, Ads là chất xúc tác, thì Trust Assets chính là mỏ neo giữ chặt niềm tin của khách hàng. Đây là tập hợp toàn bộ những tài sản số và bằng chứng thực tế giúp bệnh nhân tự kiểm chứng, gỡ bỏ sự phòng thủ và dứt khoát ra quyết định.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b625baf2-669f-4421-be25-f520f42b8e6c','bf40e5c6-ba91-4c02-89a3-c345ca9d5e27',3,'image',NULL,'book/14-trust-assets/3e1db429-d891-415f-a260-3b95ffd1ac75-img01.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f25ca3cb-851a-449d-b695-b68c8d6b1f7f','bf40e5c6-ba91-4c02-89a3-c345ca9d5e27',4,'text','Khối tài sản này không được xây dựng trong một sớm một chiều mà phải được tích lũy liên tục qua từng ca điều trị, tạo thành một hệ sinh thái bao quanh khách hàng:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1dfb6c91-0ef4-4ea5-ac86-4453690f3e59','bf40e5c6-ba91-4c02-89a3-c345ca9d5e27',5,'text','- **Case thật (Bằng chứng lâm sàng):** Hình ảnh, phim X-quang, video trước - trong - sau khi điều trị. Không gì thuyết phục bằng sự thay đổi chân thực.- **Review & Testimonial (Tiếng nói khách hàng):** Những dòng nhận xét, video phỏng vấn cảm nhận của người đã trải nghiệm.- **Google Maps:** Tọa độ địa lý minh bạch kèm theo hàng trăm đánh giá 5 sao công khai.- **Website:** Một "trụ sở online" chỉn chu, bài bản, nơi chứa đựng triết lý, đội ngũ bác sĩ và bảng giá minh bạch.- **Livestream / Q&A:** Sự xuất hiện trực tiếp, tương tác thời gian thực của bác sĩ để giải đáp thắc mắc, tạo ra sự chân thật và gần gũi tối đa.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('caa6fcfd-0693-4e98-9311-b4d07bdb2f11','14-trust-assets',NULL,2,'14.2 Mục tiêu tối thượng của Trust Assets','142-muc-tieu-toi-thuong-cua-trust-assets',1,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e8ca9b62-4891-4f12-9b4e-87086c9c8a20','caa6fcfd-0693-4e98-9311-b4d07bdb2f11',6,'image',NULL,'book/14-trust-assets/526a09e2-a340-46a3-b384-8af4e135ca54-img02.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('20cb0cdf-395c-4334-a51a-4e5fbc274004','caa6fcfd-0693-4e98-9311-b4d07bdb2f11',7,'text','Sự xuất hiện của Trust Assets trên một nền tảng Website chuẩn mực hay một kênh TikTok sinh động không phải để trang trí. Nhiệm vụ duy nhất của nó là **thúc đẩy sự dịch chuyển trạng thái tâm lý**.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f5fdcf75-f0b2-4ae0-9880-a4b777a9cd4f','caa6fcfd-0693-4e98-9311-b4d07bdb2f11',8,'text','Nó biến một người từ trạng thái *Chỉ mới biết đến (Awareness)* → Bước sang trạng thái *Tin tưởng tuyệt đối (Trust)* → Và cuối cùng là bùng nổ thành *Hành động (Action)*: Sẵn sàng inbox, gọi điện thoại, hoặc trực tiếp lái xe đến phòng khám.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8e0e4075-0893-49c5-b087-2108368fbe1e','caa6fcfd-0693-4e98-9311-b4d07bdb2f11',9,'text','Tài sản vật chất (máy móc, ghế nha) có thể hao mòn và mất giá theo thời gian. Nhưng Trust Assets thì ngược lại. Bạn càng tích lũy được nhiều ca lâm sàng thành công, càng gom được nhiều đánh giá 5 sao, thì khối tài sản này càng phình to, tạo ra một rào cản cạnh tranh khổng lồ mà không một đối thủ nào có thể dùng tiền để sao chép hay mua đứt được.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e6d13ac0-409b-4dac-bb9c-b9db112e7139','14-trust-assets',NULL,2,'14.3 Các thành phần của Trust Assets','143-cac-thanh-phan-cua-trust-assets',2,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('9f25cd05-8f63-408d-9371-c691b4f24343','14-trust-assets','e6d13ac0-409b-4dac-bb9c-b9db112e7139',3,'CASE THẬT - Bằng chứng lâm sàng, ngôn ngữ thuyết phục nhất','case-that-bang-chung-lam-sang-ngon-ngu-thuyet-phuc-nhat',3,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('798642a7-266c-44ef-ba3c-b7c0e78a8ca9','9f25cd05-8f63-408d-9371-c691b4f24343',10,'image',NULL,'book/14-trust-assets/e15b841a-23f7-47f2-ba0d-e16840bb4a41-img03.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('479b059e-e09c-493b-8190-068aaf109fce','9f25cd05-8f63-408d-9371-c691b4f24343',11,'text','Trong quá trình điều hành và chuẩn hóa các quy trình cho phòng khám RHM, tôi luôn nhấn mạnh với đội ngũ chuyên môn và truyền thông một nguyên tắc bất di bất dịch: Bệnh nhân không mua dịch vụ, họ mua kết quả và sự an tâm. Để lan tỏa tinh thần giúp mọi người thực sự **thích làm răng**, chúng ta không thể dùng những lời cam kết sáo rỗng. Chúng ta phải dùng "Case thật".',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('16eb3832-f151-416f-a21c-b2e1bf27e2fa','9f25cd05-8f63-408d-9371-c691b4f24343',12,'text','**Bản Chất Của Một Case Thật (Không Chỉ Là Hình Ảnh Trước - Sau)**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('dc60c84f-3db0-4177-bd1a-a966f22b9e6a','9f25cd05-8f63-408d-9371-c691b4f24343',13,'text','Nhiều người lầm tưởng Case thật (Ca lâm sàng thực tế) chỉ là việc ghép hai tấm ảnh Before (Trước) và After (Sau) rồi đăng lên mạng. Đó là một sự lãng phí tài nguyên. Một Case thật có sức nặng chuyển đổi phải là một câu chuyện y khoa có lớp lang, cho bệnh nhân thấy rõ 7 thành tố cốt lõi:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f05fdef3-ac63-402d-8569-6f4ec7471976','9f25cd05-8f63-408d-9371-c691b4f24343',14,'text','- **Tình trạng ban đầu:** Bệnh nhân bước vào phòng khám với vấn đề cụ thể gì? (Đau nhức, hô, móm, mất răng...).- **Mong muốn ẩn sâu:** Họ thực sự muốn cải thiện điều gì? (Ăn nhai ngon miệng hơn, hay tự tin giao tiếp để thăng tiến công việc?).- **Chẩn đoán chuyên sâu:** Dưới góc độ chuyên gia, bác sĩ nhận định nguyên nhân gốc rễ của vấn đề là gì?- **Phác đồ điều trị:** Giải pháp được đưa ra là gì? Lộ trình kéo dài bao lâu và tuân thủ theo quy trình nào?- **Kết quả thực tế:** Sự thay đổi ngoạn mục mang tính trực quan sau khi hoàn tất.- **Cảm nhận (Review):** Cảm xúc, sự tự tin và khác biệt mà bệnh nhân tự mình trải nghiệm.- **Bài học chuyên môn:** Điểm mấu chốt giải thích vì sao ca lâm sàng này lại thành công rực rỡ, khẳng định năng lực của người thực hiện.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a6e0d11a-238c-46d3-9e9a-31271786072a','9f25cd05-8f63-408d-9371-c691b4f24343',15,'text','**Bức Tranh Đa Diện: Các Loại Case Thật Cần Xây Dựng**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d0cfed94-a567-4eb9-8698-eb71c084f154','9f25cd05-8f63-408d-9371-c691b4f24343',16,'image',NULL,'book/14-trust-assets/11500790-526a-4baa-b467-09a1c9956144-img04.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('14b39954-9ead-4126-8dc4-0ae577013b24','9f25cd05-8f63-408d-9371-c691b4f24343',17,'text','Để tạo ra một mỏ neo niềm tin vững chắc, kho tài sản nội dung của chúng ta cần sự đa dạng, phục vụ cho nhiều điểm chạm tâm lý khác nhau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d6d24336-d751-4f52-9dca-0d82b38e375c','9f25cd05-8f63-408d-9371-c691b4f24343',18,'text','- **Case Trực quan (Trước – Sau):** Dành cho Niềng răng, Implant, Veneer, Tẩy trắng. Mục đích là đánh thẳng vào thị giác, chứng minh kết quả thực tế.- **Case Phân tích chuyên môn:** Đi sâu vào giải thích "Vì sao răng lệch, khớp cắn sai, mất răng lâu năm lại nguy hiểm?". Dạng này giúp định hình uy tín và hình ảnh chuyên gia cho Bác sĩ.- **Case Hành trình điều trị:** Kể lại câu chuyện biến đổi tâm lý từ lúc sợ hãi nha khoa cho đến khi tự tin mỉm cười. Dạng này tạo ra sự đồng cảm sâu sắc.- **Case Xử lý lỗi (Giáo dục thị trường):** Đưa ra các trường hợp làm răng sứ sai khớp cắn ở nơi khác gây đau nhức và cách chúng ta khắc phục. Rất hiệu quả để phá vỡ rào cản e ngại của khách hàng.- **Case Khó / Phức tạp:** Các ca Implant toàn hàm, chỉnh nha xương... nhằm định vị năng lực chuyên môn bậc cao của hệ thống Clinic.- **Case Review sau điều trị:** Bệnh nhân trực tiếp chia sẻ cảm nhận sau khi hoàn tất, tạo ra bằng chứng xã hội (Social Proof) đanh thép nhất.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('8ecf1466-3336-4fcf-bc13-2ec9b5d51b54','9f25cd05-8f63-408d-9371-c691b4f24343',19,'text','**Kỷ Luật Vận Hành: Checklist Chuẩn Cho Một Case Thật**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('bae47bf5-11e2-4e39-9b86-84b74d2df03d','9f25cd05-8f63-408d-9371-c691b4f24343',20,'image',NULL,'book/14-trust-assets/d49f80ee-0a0d-4299-b3f4-b59c7a3f2876-img05.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('19f0e84a-ada0-4352-b39b-0e6d9fc3c0e6','9f25cd05-8f63-408d-9371-c691b4f24343',21,'text','Tài sản niềm tin chỉ phát huy tác dụng khi nó được tạo ra dưới một sự kỷ luật nghiêm ngặt. Bất kỳ một Case thật nào trước khi xuất bản cũng phải vượt qua bộ lọc kiểm duyệt sau:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b152ab0d-1a17-4154-a1b1-1b563838f2c9','9f25cd05-8f63-408d-9371-c691b4f24343',22,'text','- **Hình ảnh trước điều trị:** Rõ nét, đúng góc độ y khoa, ánh sáng chân thực.- **Hình ảnh sau điều trị:** Phải chụp chuẩn xác cùng một góc độ, cùng điều kiện ánh sáng để sự so sánh là tuyệt đối khách quan.- **Mô tả vấn đề:** Ngôn từ ngắn gọn, đời thường, tránh lạm dụng thuật ngữ y khoa khó hiểu.- **Giải pháp điều trị:** Nêu rõ phương pháp kỹ thuật đã áp dụng.- **Thời gian điều trị:** Cung cấp mốc thời gian rõ ràng nếu phù hợp (rất quan trọng với niềng răng hay Implant).- **Vai trò Bác sĩ:** Hình ảnh hoặc lời bình của Bác sĩ trực tiếp lên phác đồ.- **Cảm nhận Bệnh nhân:** Có trích dẫn (Quote), video phỏng vấn hoặc lời chứng (Testimonial) gốc.- **Tính Pháp lý & Đạo đức:** Bắt buộc phải có sự xác nhận đồng ý sử dụng hình ảnh từ phía bệnh nhân trước khi công bố.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4768e707-8a85-485c-903e-ca3490d1a0ea','14-trust-assets','e6d13ac0-409b-4dac-bb9c-b9db112e7139',3,'REVIEW - Tiếng nói của khách hàng và bằng chứng xã hội','review-tieng-noi-cua-khach-hang-va-bang-chung-xa-hoi',4,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('155b3930-8afa-461a-985a-ec04ea2be950','4768e707-8a85-485c-903e-ca3490d1a0ea',23,'text','Trong kỷ nguyên tiếp thị số, một lời khen chân thành của bệnh nhân có sức nặng bằng hàng chục triệu đồng tiền chạy quảng cáo. Khi vận hành hệ thống nha khoa và nỗ lực lan tỏa tinh thần giúp mọi người xóa bỏ nỗi sợ để thực sự **thích làm răng**, tôi luôn nhắc nhở đội ngũ của mình một định lý tâm lý học bất di bất dịch:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('b7e7432e-08b2-412b-9878-31382c01d0f8','4768e707-8a85-485c-903e-ca3490d1a0ea',24,'text','**Niềm tin vào một người từng trải nghiệm > Niềm tin vào mọi lời quảng cáo của phòng khám.**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('d12648c2-c908-45c5-a9a1-800500b8cec1','4768e707-8a85-485c-903e-ca3490d1a0ea',25,'text','Review (Đánh giá) không chỉ là những ngôi sao lấp lánh trên mạng internet. Đó là phản hồi thật, là cảm xúc thật của bệnh nhân sau khi bước xuống khỏi ghế nha. Nó là thứ tài sản không thể mua bằng tiền, mà phải đánh đổi bằng mồ hôi, sự tỉ mỉ và cái tâm của toàn bộ hệ thống Clinic.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('393f62fa-0cc6-4df0-b0ec-25905dfc0554','4768e707-8a85-485c-903e-ca3490d1a0ea',26,'text','Để khai thác tối đa sức mạnh của tài sản này, chúng ta cần một chiến lược thu thập và phân bổ bài bản.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('2b546a03-a4f4-4c59-bbf9-9da72e333228','4768e707-8a85-485c-903e-ca3490d1a0ea',27,'text','**Hệ Sinh Thái Review: Đặt Đúng Chỗ Để Sinh Lời**',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1cf09b89-9743-49f2-87ae-b459763ed93c','4768e707-8a85-485c-903e-ca3490d1a0ea',28,'image',NULL,'book/14-trust-assets/8d011625-c622-4d0c-8184-4c3d8e68ddc7-img06.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('34862b89-b49c-426a-85ad-4b6b4e41d70d','4768e707-8a85-485c-903e-ca3490d1a0ea',29,'text','Không phải mọi lời khen đều giống nhau. Việc phân bổ đúng loại Review vào đúng kênh sẽ tạo ra hiệu ứng cộng hưởng mạnh mẽ nhất:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('f3fef2de-fe49-47a9-8f6e-7caf68452871','4768e707-8a85-485c-903e-ca3490d1a0ea',30,'text','- **Google Review (Trên Google Maps):** Đây là mỏ vàng để tăng cường uy tín tìm kiếm (Local SEO). Khi một người gõ "nha khoa uy tín gần đây", hàng trăm đánh giá 5 sao sẽ là yếu tố quyết định họ nhấp vào bạn thay vì đối thủ.- **Facebook Review (Trên Fanpage):** Tạo ra bằng chứng xã hội trực quan, tăng độ tin cậy ngay lập tức khi khách hàng lướt xem các bài viết quảng cáo.- **Zalo Feedback (Tin nhắn cá nhân/Zalo OA):** Chụp màn hình những đoạn chat khen ngợi chân thật là "vũ khí" tuyệt vời dành cho đội ngũ Telesale khi gửi cho khách hàng đang do dự.- **Video Testimonial (TikTok, Facebook, YouTube):** Lời nói thật, nụ cười thật, cảm xúc thật qua ống kính. Đây là đỉnh cao của Review vì nó đẩy cảm xúc và độ chân thực lên mức tối đa.- **Review trên Website / Landing Page:** Được phân loại theo từng dịch vụ (Niềng răng, Implant...) để làm đòn bẩy chốt sale ngay tại điểm chạm chuyển đổi.- **Review Nội bộ (Trên CRM):** Phản hồi sau tái khám để nhà quản trị đo lường chất lượng trải nghiệm lâm sàng thực tế.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('831237a9-9e45-407c-81ee-fc8308b8c3e2','14-trust-assets','e6d13ac0-409b-4dac-bb9c-b9db112e7139',3,'GOOGLE MAP (Tài Sản Uy Tín Địa Phương)','google-map-tai-san-uy-tin-ia-phuong',5,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('45dd1782-527b-4e93-b957-8906ed7560aa','14-trust-assets','831237a9-9e45-407c-81ee-fc8308b8c3e2',4,'Định Vị Tư Duy (The Mindset Shift)','inh-vi-tu-duy-the-mindset-shift',6,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('48dbb85d-5fa4-4901-9fb8-ff92dda15eb3','45dd1782-527b-4e93-b957-8906ed7560aa',31,'text','- **Tư duy thông thường:** Xem Google Map là một công cụ định vị đường đi cơ học, chỉ cần cập nhật địa chỉ phòng khám là đủ.- **Tư duy Dental Empire OS:** Google Map là bộ lọc xác minh uy tín thực tế tại địa phương (Local Trust Asset) và là cửa ngõ quyết định hành vi đến phòng khám (Show-up) của bệnh nhân trong bán kính mục tiêu.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('34973cdb-9fc3-4498-bca2-e3bc3506b060','14-trust-assets','831237a9-9e45-407c-81ee-fc8308b8c3e2',4,'Lý Do Chiến Lược (The Strategic Rationale)','ly-do-chien-luoc-the-strategic-rationale',7,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('c449632c-79b4-4a77-ae72-57a9dad25e36','34973cdb-9fc3-4498-bca2-e3bc3506b060',32,'text','- Google Map đóng vai trò minh bộc các đánh giá khách quan của thị trường. Một hệ thống định vị có hàng trăm lượt đánh giá thực tế từ người dùng sẽ tự động sàng lọc và thu hút tệp khách hàng có nhu cầu điều trị cao ở khu vực xung quanh phòng khám.- Đây là tài sản giúp giảm thiểu chi phí quảng cáo (CPA) dài hạn, bảo vệ dòng khách đến khám tự nhiên (Organic Show-up) thông qua thuật toán hiển thị dựa trên vị trí của Google.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4dc9df3a-7248-4552-a429-1623d856250f','14-trust-assets','831237a9-9e45-407c-81ee-fc8308b8c3e2',4,'Vòng Lặp Tác Động (The Systemic Flywheel Link)','vong-lap-tac-ong-the-systemic-flywheel-link',8,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5059d7d8-f7d9-473f-a2d4-bddf2dbb0782','4dc9df3a-7248-4552-a429-1623d856250f',33,'text','- **Domain sở hữu:** Thuộc quyền quản trị kỹ thuật của *Growth Circle* (tối ưu hóa SEO Local) nhưng nguồn nạp nguyên liệu thuộc trách nhiệm của *Patient Circle* (thu thập đánh giá thực tế từ bệnh nhân).  - *Patient Circle* thực thi SOP xin đánh giá kèm hình ảnh lâm sàng từ bệnh nhân cũ \\rightarrow Thuật toán nâng thứ hạng hiển thị của Map \\rightarrow *Growth Circle* tiếp nhận dòng khách hàng mới tìm kiếm tự nhiên trên bản đồ \\rightarrow CRM ghi nhận lịch hẹn mới.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('faa4d203-5aca-40f5-8cf6-dd4af837c740','14-trust-assets','831237a9-9e45-407c-81ee-fc8308b8c3e2',4,'Bộ Chỉ Số Quản Trị (The Governance Metrics)','bo-chi-so-quan-tri-the-governance-metrics',9,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('005b4c63-8420-4d1d-8c34-e23f41bd3e5f','faa4d203-5aca-40f5-8cf6-dd4af837c740',34,'text','- **Thứ hạng Local SEO:** Vị trí hiển thị của phòng khám trong Top 3 từ khóa ngành nha khoa tại khu vực mục tiêu.- **Tốc độ tích lũy Review:** Số lượng và tần suất các đánh giá 5 sao kèm hình ảnh thực tế được cập nhật hằng tuần.  - **Local Action Rate:** Tỷ lệ người dùng thực hiện hành vi bấm gọi hotline, nhắn tin hoặc bấm chỉ đường từ giao diện Map.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('39b929a9-b065-403b-8ced-807ce7a9ddeb','14-trust-assets','e6d13ac0-409b-4dac-bb9c-b9db112e7139',3,'WEBSITE (Trụ Sở Số Tập Trung)','website-tru-so-so-tap-trung',10,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('e434039e-e640-403f-b45c-cac1da9f1837','14-trust-assets','39b929a9-b065-403b-8ced-807ce7a9ddeb',4,'Định Vị Tư Duy (The Mindset Shift)','inh-vi-tu-duy-the-mindset-shift',11,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('42af4a24-8740-45d6-88d2-8f7aee3bf815','e434039e-e640-403f-b45c-cac1da9f1837',35,'text','- **Tư duy thông thường:** Website là một trang giới thiệu doanh nghiệp trực tuyến, một "brochure điện tử" để trưng bày hình ảnh phòng khám.- **Tư duy Dental Empire OS:** Website là lõi lưu trữ tài sản tri thức (Knowledge Hub) và là nơi đóng gói toàn bộ chứng cứ lâm sàng, năng lực y khoa của tổ chức thành tài sản số sở hữu vĩnh viễn.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a314ef3c-d64a-480c-a64a-66ee06da020e','14-trust-assets','39b929a9-b065-403b-8ced-807ce7a9ddeb',4,'Lý Do Chiến Lược (The Strategic Rationale)','ly-do-chien-luoc-the-strategic-rationale',12,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('1f39c2ee-23c1-459b-8d2b-4c3041843a34','a314ef3c-d64a-480c-a64a-66ee06da020e',36,'text','- Mạng xã hội (Social Media) là nơi phân phối nội dung ngắn, dễ bị trôi theo thời gian và thuật toán. Website là nơi duy nhất tổ chức có toàn quyền kiểm soát cấu trúc thông tin, giúp lưu trữ sâu các bài phân tích chuyên môn của Bác sĩ trưởng, hồ sơ năng lực và các Case Study thành công một cách hệ thống.  - Website giúp phân loại và giữ chân tệp khách hàng có chủ đích cao (High-intent traffic) đang tìm kiếm giải pháp cho các ca điều trị chuyên sâu (Implant, chỉnh nha), nơi mà các nội dung ngắn trên mạng xã hội chưa đủ độ sâu để thuyết phục.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3dca4679-d545-4aaa-abf2-c8d87639ebf4','14-trust-assets','39b929a9-b065-403b-8ced-807ce7a9ddeb',4,'Vòng Lặp Tác Động (The Systemic Flywheel Link)','vong-lap-tac-ong-the-systemic-flywheel-link',13,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('00954b38-8ad7-4ef9-98e6-2e87d693505f','3dca4679-d545-4aaa-abf2-c8d87639ebf4',37,'text','- **Domain sở hữu:** Thuộc quyền quản trị và tối ưu hóa của *Growth Circle.* - *Growth Circle* đóng gói các ca điều trị thành công từ *Clinical Circle* bàn giao sang thành các tài liệu chuyên môn có tính giáo dục trên Website \\rightarrow Khách hàng đọc và tự chuyển hóa lòng tin trước khi đến phòng khám \\rightarrow Giải phóng thời gian tư vấn tại ghế cho vai trò *Consultant* thuộc *Patient Circle*(), tối ưu hóa tỷ lệ chốt kế hoạch điều trị (Case Acceptance Rate).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('31f65f9c-dce0-4f3e-9751-56a7f1eec315','14-trust-assets','39b929a9-b065-403b-8ced-807ce7a9ddeb',4,'Bộ Chỉ Số Quản Trị (The Governance Metrics)','bo-chi-so-quan-tri-the-governance-metrics',14,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('329db275-f03c-4a73-98cb-20bb0bdcafc3','31f65f9c-dce0-4f3e-9751-56a7f1eec315',38,'text','- **Organic Search Traffic:** Lưu lượng truy cập tự nhiên hằng tháng từ các từ khóa chuyên môn y khoa.- **Time on Site:** Thời gian trung bình bệnh nhân ở lại đọc và nghiên cứu các tài liệu giải pháp y khoa trên trang (đo lường độ sâu của lòng tin).  - **Web Conversion Rate:** Tỷ lệ khách truy cập thực hiện hành vi để lại thông tin (Lead) hoặc bấm kết nối với cổng tư vấn (Zalo OA).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('42f71169-2a16-42f6-9d03-55393da5ee41','14-trust-assets','e6d13ac0-409b-4dac-bb9c-b9db112e7139',3,'ZALO (Zalo Official Account - Kênh Chăm Sóc &amp; Giữ Chân Tập Trung)','zalo-zalo-official-account-kenh-cham-soc-amp-giu-chan-tap-trung',15,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('50917f66-d6e2-42e9-8938-59055c1e6ff3','14-trust-assets','42f71169-2a16-42f6-9d03-55393da5ee41',4,'Định Vị Tư Duy (The Mindset Shift)','inh-vi-tu-duy-the-mindset-shift',16,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('207c47df-48a9-44db-a172-1fa2224294b2','50917f66-d6e2-42e9-8938-59055c1e6ff3',39,'text','- **Tư duy thông thường:** Zalo OA là một ứng dụng chat phụ phụ trợ, dùng để nhắn tin nhắn tin nhắn rác hoặc thông báo khuyến mãi hàng loạt cho khách hàng.- **Tư duy Dental Empire OS:** Zalo OA là kênh giao tiếp chính thức định danh của phòng khám, đóng vai trò bảo mật dữ liệu tương tác và cá nhân hóa hành trình chăm sóc khách hàng cũ tại Việt Nam.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8290d064-991b-4226-a412-4dc01d3e82fc','14-trust-assets','42f71169-2a16-42f6-9d03-55393da5ee41',4,'Lý Do Chiến Lược (The Strategic Rationale)','ly-do-chien-luoc-the-strategic-rationale',17,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('642cfcb5-1b05-4500-a11d-20cd849eb3e2','8290d064-991b-4226-a412-4dc01d3e82fc',40,'text','- Giảm sự phụ thuộc vào các nền tảng quốc tế (như Facebook Messenger) vốn dễ gặp rủi ro về thuật toán hoặc mất quyền kiểm soát trang. Zalo OA liên kết trực tiếp với số điện thoại định danh của bệnh nhân, đảm bảo tỷ lệ tiếp cận và đọc tin nhắn gần như tuyệt đối.- Hệ thống hóa toàn bộ lịch sử trò chuyện, tài liệu dặn dò hậu phẫu và hồ sơ hình ảnh ca lâm sàng của khách hàng về một nguồn sáng duy nhất (One Light), không để thông tin bị phân tán vào tài khoản cá nhân của nhân viên.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('d0bd41f7-79f7-466a-abe7-173187aad548','14-trust-assets','42f71169-2a16-42f6-9d03-55393da5ee41',4,'Vòng Lặp Tác Động (The Systemic Flywheel Link)','vong-lap-tac-ong-the-systemic-flywheel-link',18,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('cd239094-377a-4ccd-a910-2f51e4663580','d0bd41f7-79f7-466a-abe7-173187aad548',41,'text','- **Domain sở hữu:** Thuộc quyền vận hành tương tác trực tiếp của *Patient Circle* (Xử lý Inbox/CSKH)(); *Finance & Data Circle* phối hợp quản trị cấu trúc API và dữ liệu hệ thống.  - Bệnh nhân kết thúc ca điều trị tại *Clinical Circle* \\rightarrow Hệ thống tự động gửi tin nhắn dặn dò cá nhân hóa qua Zalo OA \\rightarrow Vai trò *Customer Care Specialist* theo dõi sát sao hậu phẫu qua Zalo \\rightarrow Kích hoạt tỷ lệ tái khám đúng hẹn và thu thập điểm số hài lòng (NPS).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('be2206a7-a71d-478f-8f2f-56ac2642bb2a','14-trust-assets','42f71169-2a16-42f6-9d03-55393da5ee41',4,'Bộ Chỉ Số Quản Trị (The Governance Metrics)','bo-chi-so-quan-tri-the-governance-metrics',19,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('3b8eade1-846f-40da-8fb3-a02ba9ad25b3','be2206a7-a71d-478f-8f2f-56ac2642bb2a',42,'text','- **Open Rate & Response Time:** Tỷ lệ khách hàng mở đọc tin nhắn hệ thống và thời gian trung bình tư vấn viên phản hồi tin nhắn của khách (SLA quy định).- **Active Subscriber Growth:** Tốc độ tăng trưởng lượng khách hàng thực tế nhấn quan tâm và tương tác định danh với kênh OA hằng tháng.- **Re-booking Rate via Zalo:** Tỷ lệ lịch hẹn tái khám định kỳ được đặt thành công thông qua luồng nhắc lịch tự động trên Zalo OA.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('851f769d-61fd-4aa1-b2de-1895ac1078ff','14-trust-assets','e6d13ac0-409b-4dac-bb9c-b9db112e7139',3,'ZALO MINI APP (Hệ Sinh Thái Tiện Ích &amp; Vận Hành Tự Động)','zalo-mini-app-he-sinh-thai-tien-ich-amp-van-hanh-tu-ong',20,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8fa35b5a-0558-4980-8492-3bfb31b7e53b','14-trust-assets','851f769d-61fd-4aa1-b2de-1895ac1078ff',4,'Định Vị Tư Duy (The Mindset Shift)','inh-vi-tu-duy-the-mindset-shift',21,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ba697de9-8acf-423d-98a0-75a28b7ca19b','8fa35b5a-0558-4980-8492-3bfb31b7e53b',43,'text','- **Tư duy thông thường:** Nghĩ rằng phòng khám phải đầu tư xây dựng một ứng dụng di động (App Store/Google Play) riêng biệt, tốn kém chi phí lập trình và ép khách hàng phải tải về máy.- **Tư duy Dental Empire OS:** Zalo Mini App là một hệ sinh thái tiện ích gọn nhẹ được tích hợp trực tiếp bên trong ứng dụng Zalo của khách hàng, đóng vai trò tự động hóa các thủ tục hành chính và tối ưu quyền tự chủ của bệnh nhân.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('cd6e4868-934a-4bf7-a449-fa74a00b01b8','14-trust-assets','851f769d-61fd-4aa1-b2de-1895ac1078ff',4,'Lý Do Chiến Lược (The Strategic Rationale)','ly-do-chien-luoc-the-strategic-rationale',22,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('ec323a4d-fb42-4ea8-9b36-8569c13ccb7d','cd6e4868-934a-4bf7-a449-fa74a00b01b8',44,'text','- Loại bỏ hoàn toàn rào cản tải app của bệnh nhân. Khách hàng chỉ cần quét mã QR tại phòng khám là có thể kích hoạt ngay hệ thống tiện ích mà không tốn dung lượng máy.- Đóng gói các tính năng tự phục vụ (Self-service) của bệnh nhân vào một giao diện tập trung: tự chọn lịch hẹn, tự theo dõi tiến độ thanh toán trả góp, tự kiểm tra hồ sơ bệnh án điện tử, và tự quản lý số điểm tích lũy trong cơ chế giới thiệu khách hàng (Referral Ecosystem).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('8d9fa199-a727-4873-91d6-597a139bac9a','14-trust-assets','851f769d-61fd-4aa1-b2de-1895ac1078ff',4,'Vòng Lặp Tác Động (The Systemic Flywheel Link)','vong-lap-tac-ong-the-systemic-flywheel-link',23,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('e0f06315-423d-49af-adc3-3c5d5adc0799','8d9fa199-a727-4873-91d6-597a139bac9a',45,'text','- **Domain sở hữu:** Phối hợp quản trị giữa *Finance & Data Circle* (đồng bộ dữ liệu ERP/CRM) và *Patient Circle* (điều phối lịch hẹn, quản trị cổng thành viên).  - Khách hàng sử dụng Mini App để chủ động đặt lịch khám \\rightarrow Lịch hẹn tự động đồng bộ về CRM của Lễ tân không qua trung gian \\rightarrow Khách hàng đến khám đúng giờ (Show-up Rate tăng) \\rightarrow Sau điều trị, hệ thống tự động cộng điểm thưởng tích lũy trên App \\rightarrow Khách hàng dùng điểm thưởng để đổi quà hoặc gửi mã giới thiệu cho người thân (Referral Flywheel kích hoạt).',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('f6297a69-ac2a-4009-99e7-80c4d34989c7','14-trust-assets','851f769d-61fd-4aa1-b2de-1895ac1078ff',4,'Bộ Chỉ Số Quản Trị (The Governance Metrics)','bo-chi-so-quan-tri-the-governance-metrics',24,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('71b3ad63-a849-4eb1-9a4b-6eed59b3197b','f6297a69-ac2a-4009-99e7-80c4d34989c7',46,'text','- **Mini App MAU (Monthly Active Users):** Số lượng bệnh nhân thực tế có hành vi truy cập và sử dụng các tính năng trên Mini App hằng tháng.- **In-app Booking Rate:** Phần trăm lịch hẹn được đặt trực tiếp thông qua hệ thống tự động của Mini App so với các kênh đặt lịch thủ công qua nhân viên.  - **Referral Code Activation Rate:** Tỷ lệ mã giới thiệu khách hàng mới được gửi đi và kích hoạt thành công từ ứng dụng của bệnh nhân cũ.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('28966b1d-25ee-4049-a7e1-d1e8feebd540','14-trust-assets','e6d13ac0-409b-4dac-bb9c-b9db112e7139',3,'LIVESTREAM (Truyền Thông Minh Bạch Thực Tại)','livestream-truyen-thong-minh-bach-thuc-tai',25,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('0b935a44-9ecf-4f2e-8d2d-03d79cbca463','14-trust-assets','28966b1d-25ee-4049-a7e1-d1e8feebd540',4,'Định Vị Tư Duy (The Mindset Shift)','inh-vi-tu-duy-the-mindset-shift',26,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('5cff13c7-b35b-4a5c-b163-a9a03c04ce07','0b935a44-9ecf-4f2e-8d2d-03d79cbca463',47,'text','- **Tư duy thông thường:** Livestream là hoạt động lên hình để bán hàng giảm giá, chốt đơn thương mại điện tử hoặc tổ chức mini-game giải trí câu tương tác.- **Tư duy Dental Empire OS:** Livestream là tài sản truyền thông minh bạch hóa thực tại (Transparency Media), đóng vai trò phơi bày toàn bộ tiêu chuẩn vận hành, công nghệ và năng lực y khoa thực tế dưới một nguồn sáng duy nhất (One Light) trước thị trường.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('c1c14d81-765f-4a7c-8929-298fba401c93','14-trust-assets','28966b1d-25ee-4049-a7e1-d1e8feebd540',4,'Lý Do Chiến Lược (The Strategic Rationale)','ly-do-chien-luoc-the-strategic-rationale',27,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('616dacff-c0c7-4fb0-bcf5-58545f32fe89','c1c14d81-765f-4a7c-8929-298fba401c93',48,'text','- Trong ngành nha khoa, rào cản lớn nhất của khách hàng mới là nỗi sợ: sợ đau, sợ quảng cáo giả mạo, sợ bác sĩ non tay nghề. Livestream giải quyết triệt để nỗi sợ này bằng chứng cứ thời gian thực (Real-time Proof). Việc đưa camera trực tiếp vào quy trình tư vấn lâm sàng, quy trình vô trùng khép kín, hay hình ảnh tháo băng chỉnh nha thực tế sẽ bẻ gãy mọi sự hoài nghi của người xem.  - Gia tốc tiến trình ra quyết định của các Lead đang phân vân. Sức mạnh của sự tương tác trực tiếp, giải đáp y khoa trực quan từ Bác sĩ trưởng trên phiên live có giá trị thuyết phục cao hơn hàng loạt bài viết quảng cáo tĩnh.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('41ce9b75-b990-41d3-8309-385545fc0662','14-trust-assets','28966b1d-25ee-4049-a7e1-d1e8feebd540',4,'Vòng Lặp Tác Động (The Systemic Flywheel Link)','vong-lap-tac-ong-the-systemic-flywheel-link',28,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('a715a6f6-e0d2-4ae2-9810-87d1ee689c9d','41ce9b75-b990-41d3-8309-385545fc0662',49,'text','- **Domain sở hữu:** Phối hợp thực thi giữa *Growth Circle* (Kỹ thuật phiên live, kịch bản điều phối), *Clinical Circle* (Bảo đảm tiêu chuẩn chuyên môn y khoa khi ghi hình)() và *Patient Circle* (Trực chiến chuyển đổi dữ liệu).  - *Growth Circle* kích hoạt phiên live minh bộc ca lâm sàng chuẩn xác từ *Clinical Circle*\\rightarrow Người xem phát sinh nhu cầu và để lại thông tin trực tiếp trong phiên live \\rightarrow Vai trò *Tele-sales/Booking Specialist* thuộc *Patient Circle* tiếp nhận dữ liệu thời gian thực và chốt lịch hẹn ngay lập tức.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('2e68704e-4ea7-48fa-8314-8ae79d7b5a11','14-trust-assets','28966b1d-25ee-4049-a7e1-d1e8feebd540',4,'Bộ Chỉ Số Quản Trị (The Governance Metrics)','bo-chi-so-quan-tri-the-governance-metrics',29,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('9e2285a7-a39b-413d-a7c5-07233b549d74','2e68704e-4ea7-48fa-8314-8ae79d7b5a11',50,'text','- **Concurrent Viewers & Retention Rate:** Số lượng người xem đồng thời tại một thời điểm và thời gian giữ chân người xem trung bình trong phiên live.- **In-live Engagement Rate:** Phần trăm người xem thực hiện hành vi đặt câu hỏi chuyên môn, tương tác trực tiếp với Bác sĩ điều phối.- **Lead-per-Live (LPL):** Số lượng dữ liệu khách hàng hoặc lịch hẹn định danh thu được và xử lý thành công trực tiếp trong chu kỳ phát sóng.',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('19445170-2c99-4e58-ab23-88f275a0d2a7','14-trust-assets',NULL,2,'14.8 Vì sao niềm tin cần được đóng gói thành tài sản?','148-vi-sao-niem-tin-can-uoc-ong-goi-thanh-tai-san',30,'[]');
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('981341ee-5910-4687-9b05-faf8ecffb14c','19445170-2c99-4e58-ab23-88f275a0d2a7',51,'text','Để hiểu tại sao hệ điều hành `Dental Empire OS` không gọi "niềm tin" là một trạng thái cảm xúc, mà bắt buộc phải gọi là **Tài sản uy tín (Trust Assets)**, tổ chức cần giải phẫu tư duy qua **Khung Nhận Thức 4 Chiều**:',NULL,NULL,NULL,NULL,NULL);
INSERT OR IGNORE INTO block (id,section_id,`order`,type,text_md,r2_key,filename,mime,alt,caption) VALUES ('55d4cb99-ad07-494f-9a17-a3bddf0353a5','19445170-2c99-4e58-ab23-88f275a0d2a7',52,'image',NULL,'book/14-trust-assets/c9fc57c3-8255-4273-9546-ed2b6c875615-img07.png','image.png','image/png','image.png',NULL);
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('4a006c9e-9129-4297-aa7f-19ce1346e16b','14-trust-assets','19445170-2c99-4e58-ab23-88f275a0d2a7',3,'Định vị Tư duy (The Mindset Shift)Tư duy thông thường: Nghĩ rằng niềm tin là thứ vô hình, nằm trong đầu khách hàng và phụ thuộc vào sự khéo léo, duyên dáng của cá nhân tư vấn viên hoặc bác sĩ khi đối thoại trực tiếp.Tư duy Dental Empire OS: Niềm tin là một dạng năng lượng có thể định lượng, có thể tích lũy, có thể sở hữu và cấu trúc hóa vĩnh viễn. Nếu không được "đóng gói", niềm tin sẽ bốc hơi theo thời gian hoặc biến mất ngay khi nhân sự giỏi của bạn rời đi.','inh-vi-tu-duy-the-mindset-shifttu-duy-thong-thuong-nghi-rang-niem-tin-la-thu-vo-',31,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('3b8790d9-5d79-4827-990a-872a29fe0cdf','14-trust-assets','19445170-2c99-4e58-ab23-88f275a0d2a7',3,'Lý do Chiến lược (The Strategic Rationale)Phá vỡ bẫy chi phí Marketing gia tăng (CPA): Trên thị trường nha khoa cạnh tranh khốc liệt, chi phí để mua một khách hàng mới (CPL/CPA) ngày càng đắt đỏ. Khi bạn đóng gói niềm tin thành các tài sản hữu hình (Hệ thống Case Study, Video quy trình y khoa, hàng nghìn đánh giá Map công khai), bạn đang tạo ra một bộ lọc tự động thuyết phục khách hàng trước khi họ đến phòng khám. Điều này giúp giảm sụt giảm tỷ lệ chuyển đổi và hạ thấp chi phí thu hút tổng về dài hạn.  Giải phóng năng lượng tại ghế (Chairside Efficiency): Nếu khách hàng bước vào phòng khám với sự hoài nghi, Bác sĩ và Tư vấn viên (Consultant) sẽ phải mất 60–90 phút chỉ để giải thích và thuyết phục. Ngược lại, khi niềm tin đã được đóng gói và "tiêu hóa" trước qua hệ thống Trust Assets, khách hàng đến khám chỉ để xác nhận lại phương án tài chính. Tốc độ chốt ca (Case Acceptance Rate) tăng vọt, giải phóng công suất cho ghế nha.','ly-do-chien-luoc-the-strategic-rationalepha-vo-bay-chi-phi-marketing-gia-tang-cp',32,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('a35a908a-699b-4612-93de-0636745eb730','14-trust-assets','19445170-2c99-4e58-ab23-88f275a0d2a7',3,'Vòng lặp Tác động (The Systemic Impact)Khi niềm tin được số hóa và đóng gói thành tài sản, nó sẽ chạy tự động hằng ngày hằng giờ trên môi trường số để nuôi dưỡng Acquisition Engine (Động cơ thu hút khách mới).  Tài sản uy tín này là nguyên liệu đầu vào giúp Patient Circle tối ưu hóa tỷ lệ đặt hẹn (Lead-to-Book), giúp Clinical Circle tăng uy tín chuyên môn y khoa, và gián tiếp tạo ra năng lượng thặng dư nuôi sống bánh đà tăng trưởng kép của toàn bộ phòng khám (tầng Prosper).','vong-lap-tac-ong-the-systemic-impactkhi-niem-tin-uoc-so-hoa-va-ong-goi-thanh-tai',33,'[]');
INSERT OR IGNORE INTO section (id,chapter_id,parent_id,level,title,slug,`order`,keywords) VALUES ('7d0b4118-425d-4f2e-a43f-7e21c1f0ade3','14-trust-assets','19445170-2c99-4e58-ab23-88f275a0d2a7',3,'Bộ chỉ số Đo lường (The Governance Metrics)Tổ chức định giá và kiểm soát khối lượng "Tài sản uy tín" này trên Dashboard thông qua:Tỷ lệ Chuyển đổi Tự nhiên (Organic CR): Phần trăm khách hàng tự tìm đến phòng khám và đồng ý điều trị mà không qua các chương trình khuyến mãi hay chèo kéo.  Tốc độ Tích lũy Tài sản: Số lượng Case Study thành công được nghiệm thu và đóng gói thành tư liệu truyền thông hằng tháng.  Chỉ số CPA-to-LTV Margin: Biên độ chênh lệch ngày càng lớn giữa Chi phí thu hút khách hàng (CPA) ngày càng giảm và Giá trị vòng đời khách hàng (LTV) ngày càng tăng nhờ lòng tin bền vững.','bo-chi-so-o-luong-the-governance-metricsto-chuc-inh-gia-va-kiem-soat-khoi-luong-',34,'[]');
